import * as React from 'react';
import { Text, Input, Divider } from '@universe-design/react';

const defaultFontFamilyList = `LarkHackSafariFont, LarkEmojiFont, LarkChineseQuote,
Lark Circular, -apple-system, BlinkMacSystemFont, Helvetica Neue, Tahoma, PingFang SC, Microsoft Yahei,
Arial, Hiragino Sans GB, sans-serif, Apple Color Emoji, Segoe UI Emoji,
Segoe UI Symbol, Noto Color Emoji`;

export const FontFamilyTest = () => {
  // eslint-disable-next-line @typescript-eslint/no-magic-numbers
  const fontWeights = [400, 500, 600, 700];

  const defaultTestText = `
  简中：门、骨、直、径、禅、关、画
繁中：選擇 詳細
英语：G Q t y 1 3 , “ ” " " ‘ ’ '；
日语汉字：画面、詳細、直近
日语假名：こんにちは チャット
西意德法葡印尼：Greña / L’italiano / wäßrig / Français / limões
越南：Ỏ Ẳ
泰：ประเทศไทย
韩：한국어
俄：ѳ у
印地：औ ध भ
`;
  const [text, setText] = React.useState(defaultTestText);
  const [fontFamily, setFontFamily] = React.useState(defaultFontFamilyList);

  const str2SpanList = (s: string, sep?: RegExp) =>
    s.split(sep ? sep : '').map((ch, index) => (
      <span key={ch + index}>
        <span>{ch}</span>
      </span>
    ));

  return (
    <div>
      <Divider text="设置区" />

      <div>
        <Text>测试文本： </Text>
        <Input.TextArea value={text} onChange={e => setText(e.target.value)} />
        <Text>font-family： </Text>
        <Input.TextArea value={fontFamily} onChange={e => setFontFamily(e.target.value)} />
      </div>
      {fontWeights.map(fw => (
        <p key={fw} style={{ fontWeight: fw, fontFamily }}>
          font-weight: {fw} {str2SpanList(text)}
        </p>
      ))}
    </div>
  );
};
